package com.hospital.management.controller.appointment;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.AppointmentServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.sql.SQLException;
@WebServlet("/appointments/create")public class AppointmentCreateServlet extends HttpServlet {private final AppointmentService service;public AppointmentCreateServlet(){this(new AppointmentServiceImpl());}public AppointmentCreateServlet(AppointmentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{show(q,r,new AppointmentForm());}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{AppointmentForm f=AppointmentRequest.form(q);ServiceResult<Long>x=service.createAppointment(f,AppointmentRequest.audit(q),AppointmentRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/appointments?message=created");return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f);}private void show(HttpServletRequest q,HttpServletResponse r,AppointmentForm f)throws ServletException,IOException{q.setAttribute("appointmentForm",f);q.setAttribute("formMode","CREATE");try{q.setAttribute("patients",new PatientDaoImpl().findAll(new PageRequest(1,100,""),"ACTIVE").getContent());q.setAttribute("doctors",new DoctorDaoImpl().findActiveDoctors());}catch(SQLException e){q.setAttribute("patients",java.util.List.of());q.setAttribute("doctors",java.util.List.of());}q.getRequestDispatcher("/WEB-INF/views/appointments/form.jsp").forward(q,r);}}
